#include<bits/stdc++.h>
using namespace std;

const int N = 5e5 + 5;

vector<int> g[N];
int up[N][20], sz[N], dep[N], tin[N], tout[N], cnt;

void dfs(int u, int p) {
    up[u][0] = p;
    sz[u] = 1;
    tin[u] = ++cnt;
    dep[u] = dep[p] + 1;
    for (int i = 1; i < 20; i++)
        up[u][i] = up[up[u][i-1]][i-1];
    for (int v : g[u]) {
        if (v != p) {
            dfs(v, u);
            sz[u] += sz[v];
        }
    }
    tout[u] = cnt;
}

int lca(int x, int y) {
    if (dep[x] < dep[y]) swap(x, y);
    int diff = dep[x] - dep[y];
    for (int i = 0; i < 20; i++)
        if (diff >> i & 1)
            x = up[x][i];
    if (x == y) return x;
    for (int i = 19; i >= 0; i--)
        if (up[x][i] != up[y][i])
            x = up[x][i], y = up[y][i];
    return up[x][0];
}

bool is_anc(int x, int y) {
    return tin[x] <= tin[y] && tout[y] <= tout[x];
}

int jump_child(int x, int anc) {
    if (x == anc) return 0;
    for (int i = 19; i >= 0; i--)
        if (dep[up[x][i]] > dep[anc])
            x = up[x][i];
    return sz[x];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, q;
    cin >> n >> q;
    for (int i = 1; i < n; i++) {
        int u, v;
        cin >> u >> v;
        g[u].push_back(v);
        g[v].push_back(u);
    }

    dfs(1, 0);

    while (q--) {
        int a, b, c;
        cin >> a >> b >> c;

        int l = lca(a, b);

        if (l == c) {
            cout << n - jump_child(a, c) - jump_child(b, c) << '\n';
        } else if (is_anc(c, a) && !is_anc(c, b)) {
            cout << sz[c] - jump_child(a, c) << '\n';
        } else if (is_anc(c, b) && !is_anc(c, a)) {
            cout << sz[c] - jump_child(b, c) << '\n';
        } else {
            cout << "0\n";
        }
    }

    return 0;
}
